      "Basic conceptual understanding of content",
      "Use of SI units and international standards",
      "Process-skills (experimental, observational, manipulative)",
      "Problem-solving abilities",
      "Creative thinking"
    ],
    "bloom_levels": [
      {
        "level": "Remembering",
        "description": "Exhibit memory of previously learned material by recalling facts, terms, basic concepts."
      },
      {
        "level": "Understanding",
        "description": "Demonstrate understanding by organizing, comparing, translating, interpreting ideas."
      },
      {
        "level": "Applying",
        "description": "Solve problems to new situations using acquired knowledge and rules."
      },
      {
        "level": "Analysing/Evaluating/Creating",
        "description": "Examine information, make judgments based on criteria, combine elements in a new pattern."
      }
    ],
    "internal_assessment": [
      "Content excluded from NCERT textbooks for 2026-27 is not to be tested by schools.",
      "Internal variations may be made keeping overall weightage same as the sample template."
    ],
    "practical_assessment": {
      "theory_marks": 30,
      "duration_hours": 3,
      "components": [
        {
          "item": "Two experiments (one from each section)",
          "marks": 14
        },
        {
          "item": "Practical record (experiments and activities)",
          "marks": 5
        },
        {
          "item": "One activity from any section",
          "marks": 3
        },
        {
          "item": "Investigatory Project",
          "marks": 3
        },
        {
          "item": "Viva on experiments, activities and project",
          "marks": 5
        }
      ],
      "requirements": [
        "Record of at least 8 Experiments (4 from Section A, 4 from Section B)",
        "Record of at least 6 Activities (3 from Section A, 3 from Section B)"
      ]
    },
    "project_assessment": {
      "marks": 3,
      "description": "Report of the project carried out by students",
      "examples": [
        "Study factors on which internal resistance/EMF of a cell depends.",
        "Variations in current flowing in circuit containing LDR due to lamp power/distance variations.",
        "Refractive indices of water/oil using plane mirror and lens.",
        "Relation between output/input voltage and turns ratio in transformer.",
        "Dependence of angle of deviation on incidence angle using hollow prism.",
        "Charge induced on Styrofoam balls using Coulomb's law.",
        "Self-inductance dependence on coil factors.",
        "Earth's magnetic field study."
      ]
    }
  }
